import 'dart:convert'; import 'package:flutter_secure_storage/flutter_secure_storage.dart'; import 'package:injectable/injectable.dart'; @singleton class SecureStorageService { final FlutterSecureStorage _storage; SecureStorageService(this._storage); Future<void> write(String key, String value) => _storage.write(key: key, value: value); Future<String?> read(String key) => _storage.read(key: key); Future<void> delete(String key) => _storage.delete(key: key); Future<void> deleteAll() => _storage.deleteAll(); Future<bool> containsKey(String key) => _storage.containsKey(key: key); Future<void> writeJson(String key, Map<String, dynamic> value) => _storage.write(key: key, value: jsonEncode(value)); Future<Map<String, dynamic>?> readJson(String key) async { final r = await _storage.read(key: key); return r != null ? Map<String, dynamic>.from(jsonDecode(r)) : null; } }